import{_ as t,o as i,c as o,a2 as a}from"./chunks/framework.D5wUhsuj.js";const h=JSON.parse('{"title":"GitHub Actions CI/CD","description":"","frontmatter":{},"headers":[],"relativePath":"development/06-github-actions.md","filePath":"development/06-github-actions.md"}'),n={name:"development/06-github-actions.md"};function r(l,e,d,c,u,s){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="github-actions-ci-cd" tabindex="-1">GitHub Actions CI/CD <a class="header-anchor" href="#github-actions-ci-cd" aria-label="Permalink to &quot;GitHub Actions CI/CD&quot;">​</a></h1><h2 id="prehled" tabindex="-1">Přehled <a class="header-anchor" href="#prehled" aria-label="Permalink to &quot;Přehled&quot;">​</a></h2><p>GitHub Actions slouží jako automatizovaná vývojová pipeline. Zajišťuje čistý a nezávislý build mimo lokální Termux prostředí.</p><h2 id="architektura-ci" tabindex="-1">Architektura CI <a class="header-anchor" href="#architektura-ci" aria-label="Permalink to &quot;Architektura CI&quot;">​</a></h2><p>Developer -&gt; git push -&gt; GitHub -&gt; Ubuntu Runner -&gt; NPM Build -&gt; Capacitor Sync -&gt; Gradle Build -&gt; APK Artifact</p><h2 id="aktualni-technologie" tabindex="-1">Aktuální technologie <a class="header-anchor" href="#aktualni-technologie" aria-label="Permalink to &quot;Aktuální technologie&quot;">​</a></h2><ul><li>GitHub Actions (Ubuntu Runner)</li><li>Node.js (pro Vite)</li><li>JDK 21 &amp; Gradle 8.x</li><li>Android SDK &amp; Capacitor</li></ul><h2 id="doporucene-kroky-pipeline" tabindex="-1">Doporučené kroky pipeline <a class="header-anchor" href="#doporucene-kroky-pipeline" aria-label="Permalink to &quot;Doporučené kroky pipeline&quot;">​</a></h2><p><strong>1. Checkout:</strong> Stažení zdrojového kódu (<code>actions/checkout</code>). <strong>2. Setup Node &amp; Java:</strong> Příprava prostředí pro kompilaci. <strong>3. Instalace závislostí:</strong> <code>npm install</code>. <strong>4. Frontend Build (Kritický krok):</strong> <code>npm run build</code>. <strong>5. Capacitor Sync:</strong> <code>npx cap sync android</code>. <strong>6. Android Build:</strong> <code>cd android &amp;&amp; ./gradlew assembleDebug</code>.</p><h2 id="historicke-milniky-ci" tabindex="-1">Historické milníky CI <a class="header-anchor" href="#historicke-milniky-ci" aria-label="Permalink to &quot;Historické milníky CI&quot;">​</a></h2><ul><li><strong>Gradle &amp; JDK 21 upgrade:</strong> Příprava na moderní standardy.</li><li><strong>Odstranění Cordova závislostí:</strong> Přidán auditovatelný skript (bývalý commit e668899) pro odstranění nepotřebných pluginů, čímž se odlehčil build.</li></ul><h2 id="budouci-rozsireni" tabindex="-1">Budoucí rozšíření <a class="header-anchor" href="#budouci-rozsireni" aria-label="Permalink to &quot;Budoucí rozšíření&quot;">​</a></h2><ul><li>Automatické nahrávání APK jako Artifactu pro okamžité stažení z GitHubu.</li><li>Automatický deployment Node.js backendu na AWS při změně ve větvi main.</li></ul>',13)])])}const k=t(n,[["render",r]]);export{h as __pageData,k as default};
